            const nodeData = $node[nodeName].json;

            // Check if this node has username and password
            if (nodeData.username && nodeData.username !== "unknown") {
                userData.username = nodeData.username;
                userData.newPassword = nodeData.newPassword || userData.newPassword;
                userData.base64Username = nodeData.base64Username || "";
                userData.base64Password = nodeData.base64Password || "";
