            // Check if data is nested
            else if (nodeData.originalData && nodeData.originalData.data) {
                userData.username = atob(nodeData.originalData.data.username) || "unknown";
                userData.newPassword = atob(nodeData.originalData.data.password) || "unknown";
                console.log(`Found user data in nested data from node: ${nodeName}`);
                break;
            }
        }
