}

// Initialize status
let secretExists = false;
let errorMessage = "";
let statusCode = 500;

// Check if there's an error (404 case)
if (httpResponse && httpResponse.error) {
    secretExists = false;
    statusCode = httpResponse.error.status || 404;
    errorMessage = "Secret 'db-credentials' not found in namespace 'default'";
}
// Check for HTTP status code error
else if (httpResponse && httpResponse.code && httpResponse.code !== 200) {
    secretExists = false;
    errorMessage = httpResponse.message || `HTTP Error ${httpResponse.code}`;
    statusCode = httpResponse.code;
    if (httpResponse.code === 404) {
        errorMessage = "Secret 'db-credentials' not found in namespace 'default'";
    }
}
// Check for successful response
else if (httpResponse && (httpResponse.metadata || httpResponse.data)) {
    secretExists = true;
    errorMessage = "";
    statusCode = 200;
}
// No data or unknown error
else {
    secretExists = false;
    errorMessage = "No response received from Kubernetes API - secret may not exist";
    statusCode = 404;
}

// Return the result with credentials
return [
    {
        json: {
            // Credentials
            username: userData.username || "unknown",
            newPassword: userData.newPassword || "unknown",
            base64Username: userData.base64Username || "",
            base64Password: userData.base64Password || "",

            // Status
            secretExists: secretExists,
            success: secretExists,
            statusCode: statusCode,
            errorMessage: errorMessage,

            // Timestamp
            timestamp: new Date().toISOString(),
            formattedTime: new Date().toLocaleString()
        }
    }
];

// Get all items
const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
    const postgresResult = items[i].json;

    // Get user data from password generator node
    let userData = { username: "unknown", newPassword: "unknown" };
    try {
        if ($node['Code in JavaScript'] && $node['Code in JavaScript'].json) {
            userData = $node['Code in JavaScript'].json;
        }
    } catch (e) {
        // Use data from postgres result if available
        if (postgresResult && postgresResult.username) {
            userData.username = postgresResult.username;
        }
    }

    // Check if PostgreSQL update was successful
    let postgresSuccess = false;
    let errorMessage = "";
    let statusCode = 200;

    if (postgresResult && postgresResult.success === true) {
        postgresSuccess = true;
    } 
    else if (postgresResult && postgresResult.error) {
        postgresSuccess = false;
        errorMessage = postgresResult.error.message || "PostgreSQL ALTER USER failed";
        statusCode = 500;
    } 
    else if (postgresResult && Object.keys(postgresResult).length > 0) {
        postgresSuccess = true;
    } 
    else {
        postgresSuccess = false;
        errorMessage = "PostgreSQL ALTER USER failed - no response";
        statusCode = 500;
    }

    results.push({
        json: {
            username: userData.username,
            newPassword: userData.newPassword,
            postgresSuccess: postgresSuccess,
            errorMessage: errorMessage,
            statusCode: statusCode,
            timestamp: new Date().toISOString(),
            formattedTime: new Date().toLocaleString()
        }
    });
}

return results;

// Get the restart deployment result (this contains the HTTP response or error)
const restartData = $input.first().json;

// Get user data from password generator node
const userData = $node['Code in JavaScript'].json;

// Initialize variables
let success = false;
let errorMessage = "";
let failedStep = "";
let deploymentName = "pgbouncer";

// Check what kind of response we got
if (restartData) {
    // Case 1: n8n error object (when Continue on Fail is enabled)
    if (restartData.error) {
        success = false;
        errorMessage = restartData.error.message || "Unknown error occurred";
        failedStep = "HTTP Request1 (Restart Deployment)";

        // Check for 404 not found
        if (errorMessage.includes("404") || errorMessage.includes("not found")) {
            failedStep = "Deployment Restart (404 Not Found)";
            errorMessage = "Deployment 'db-test-deployment' not found in Kubernetes cluster";
        }
    }
    // Case 2: HTTP Error Response with code
    else if (restartData.code && restartData.code !== 200) {
        success = false;
        errorMessage = restartData.message || `HTTP Error ${restartData.code}`;
        failedStep = "Kubernetes API - Restart Deployment";

        if (restartData.code === 404) {
            errorMessage = "Deployment 'db-test-deployment' not found";
            failedStep = "Deployment Restart (404 Not Found)";
        }
    }
    // Case 3: Successful response with metadata
    else if (restartData.metadata && restartData.metadata.name) {
        success = true;
        errorMessage = "";
        failedStep = "";
        deploymentName = restartData.metadata.name;
    }
    // Case 4: Any other case - consider as failure
    else {
        success = false;
        errorMessage = "Deployment restart failed - unexpected response from Kubernetes API";
        failedStep = "Kubernetes API";
    }
} else {
    // Case 5: No data returned
    success = false;
    errorMessage = "No response received from Kubernetes API - deployment may not exist";
    failedStep = "Kubernetes API";
}

// ALWAYS return username and password, even on failure
return [
    {
        json: {
            username: userData.username,
            newPassword: userData.newPassword,
            success: success,
            errorMessage: errorMessage,
            failedStep: failedStep,
            timestamp: new Date().toISOString(),
            deploymentName: deploymentName,
            status: success ? "SUCCESS" : "FAILED"
        }
    }
